1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
3	type QuoteInput = { customer: Customer; items: Item[] };
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE = 0.1;
14	
15	export function quote(input: QuoteInput): { premium: number } {
16	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
17	
18	  const item = input.items[0];
19	  let policyBase = BASE_PREMIUMS[item.type];
20	  if (input.customer.previousContracts === 0) {
21	    policyBase = policyBase * (1 + FIRST_INSURANCE_SURCHARGE);
22	  }
23	  const total = Math.ceil(Math.round(policyBase * 100) / 100 + PROCESSING_FEE);
24	  return { premium: total };
25	}
26	
27	export function claim(_input: unknown): { payout: number } {
28	  return { payout: 0 };
29	}
